+	#load(search: string) {
+		const id = ++this.#requestId;
+		this.#clearTimer('debounce');
+		this.#clearTimer('retry');
+		this.#clearTimer('min');
+		this.loadError = '';
+		this.retryCount = 0;
+		if (search.length > 0 && search.length < this.#minSearchLength) {
+			this.#abortFetch();
+			this.loading = false;
+			this.searchTooShort = true;
+			this.#setOptions([]);
+			this._rerender();
+			return;
+		}
+		this.searchTooShort = false;
+		const cached = this.#cacheResults ? this.#cache.get(search) : undefined;
+		if (cached && !this.#staleWhileRevalidate) {
+			this.#abortFetch();
+			this.loading = false;
+			this.#setOptions(cached);
+			this._rerender();
+			return;
+		}
+		if (cached) this.#setOptions(cached);
+		this.loading = true;
+		this._rerender();
+		this.#debounceTimer = setTimeout(() => this.#beginFetch(search, id, 0), this.#debounceMs);
+	}
