+	#beginFetch(search: string, id: number, attempt: number) {
+		if (id !== this.#requestId || this.searchTooShort) return;
+		this.#debounceTimer = undefined;
+		this.#abortFetch();
+		const controller = new AbortController();
+		this.#controller = controller;
