+		try {
+			result = (this.#options as OptionsResolver<T>).call(this, search, { signal: controller.signal });
+		} catch (error) {
+			this.#handleFetchError(search, id, attempt, error);
+			return;
+		}
+		this.#consumeFetch(search, id, result, attempt, Date.now());
+	}
+
+	#consumeFetch(search: string, id: number, result: T[] | PromiseLike<T[]>, attempt: number, started: number) {
+		Promise.resolve(result).then(
+			(options) => this.#finishFetch(search, id, options, started),
+			(error) => this.#handleFetchError(search, id, attempt, error)
+		);
+	}
+
+	#finishFetch(search: string, id: number, options: T[], started: number) {
+		if (id !== this.#requestId || this.searchTooShort) return;
+		this.#controller = undefined;
+		this.#storeCache(search, options);
+		const apply = () => {
+			if (id !== this.#requestId || this.searchTooShort) return;
+			this.loading = false;
+			this.loadError = '';
+			this.retryCount = 0;
+			this.#setOptions(options);
+			this._rerender();
+		};
