+	#handleFetchError(search: string, id: number, attempt: number, error: unknown) {
+		if (id !== this.#requestId || this.searchTooShort) return;
+		this.#controller = undefined;
+		if ((error as { name?: string })?.name === 'AbortError') {
+			this.loading = false;
+			this._rerender();
+			return;
+		}
